     370: static char *
     371: format_job_get(struct format_expand_state *es, const char *cmd)
     372: {
     373: 	struct format_tree		*ft = es->ft;
     374: 	struct format_job_tree		*jobs;
     375: 	struct format_job		 fj0, *fj;
     376: 	time_t				 t;
     377: 	char				*expanded;
     378: 	int				 force;
     379: 	struct format_expand_state	 next;
     380: 
     381: 	if (ft->client == NULL)
     382: 		jobs = &format_jobs;
     383: 	else if (ft->client->jobs != NULL)
     384: 		jobs = ft->client->jobs;
     385: 	else {
>>   386: 		jobs = ft->client->jobs = xmalloc(sizeof *ft->client->jobs);
     387: 		RB_INIT(jobs);
     388: 	}
     389: 
     390: 	fj0.tag = ft->tag;
     391: 	fj0.cmd = cmd;
     392: 	if ((fj = RB_FIND(format_job_tree, jobs, &fj0)) == NULL) {
     393: 		fj = xcalloc(1, sizeof *fj);
     394: 		fj->client = ft->client;
     395: 		fj->tag = ft->tag;
     396: 		fj->cmd = xstrdup(cmd);
     397: 
     398: 		RB_INSERT(format_job_tree, jobs, fj);
     399: 	}
     400: 
     401: 	format_copy_state(&next, es, FORMAT_EXPAND_NOJOBS);
     402: 	next.flags &= ~FORMAT_EXPAND_TIME;
     403: 
     404: 	expanded = format_expand1(&next, cmd);
     405: 	if (fj->expanded == NULL || strcmp(expanded, fj->expanded) != 0) {
     406: 		free((void *)fj->expanded);
     407: 		fj->expanded = xstrdup(expanded);
     408: 		force = 1;
     409: 	} else
     410: 		force = (ft->flags & FORMAT_FORCE);
     411: 
     412: 	t = time(NULL);
     413: 	if (force && fj->job != NULL)
     414: 	       job_free(fj->job);
     415: 	if (force || (fj->job == NULL && fj->last != t)) {
     416: 		fj->job = job_run(expanded, 0, NULL, NULL, NULL,
     417: 		    server_client_get_cwd(ft->client, NULL), format_job_update,
     418: 		    format_job_complete, NULL, fj, JOB_NOWAIT, -1, -1);
     419: 		if (fj->job == NULL) {
     420: 			free(fj->out);
     421: 			xasprintf(&fj->out, "<'%s' didn't start>", fj->cmd);
     422: 		}
     423: 		fj->last = t;
     424: 		fj->updated = 0;
     425: 	} else if (fj->job != NULL && (t - fj->last) > 1 && fj->out == NULL)
     426: 		xasprintf(&fj->out, "<'%s' not ready>", fj->cmd);
     427: 	free(expanded);
     428: 
     429: 	if (ft->flags & FORMAT_STATUS)
     430: 		fj->status = 1;
     431: 	if (fj->out == NULL)
     432: 		return (xstrdup(""));
     433: 	return (format_expand1(&next, fj->out));
     434: }

    4292: static struct format_modifier *
    4293: format_build_modifiers(struct format_expand_state *es, const char **s,
    4294:     u_int *count)
    4295: {
    4296: 	const char		*cp = *s, *end;
    4297: 	struct format_modifier	*list = NULL;
    4298: 	char			 c, last[] = "X;:", **argv, *value;
    4299: 	int			 argc;
    4300: 
    4301: 	/*
    4302: 	 * Modifiers are a ; separated list of the forms:
    4303: 	 *	l,m,C,a,b,c,d,n,t,w,q,E,T,S,W,P,R,<,>
    4304: 	 *	=a
    4305: 	 *	=/a
    4306: 	 *	=/a/
    4307: 	 *	s/a/b/
    4308: 	 *	s/a/b
    4309: 	 *	||,&&,!=,==,<=,>=
    4310: 	 */
    4311: 
    4312: 	*count = 0;
    4313: 
    4314: 	while (*cp != '\0' && *cp != ':') {
    4315: 		/* Skip any separator character. */
    4316: 		if (*cp == ';')
    4317: 			cp++;
    4318: 		if (*cp == '\0')
    4319: 			break;
    4320: 
    4321: 		/* Check single character modifiers with no arguments. */
    4322: 		if (strchr("labcdnwETSWPL!<>", cp[0]) != NULL &&
    4323: 		    format_is_end(cp[1])) {
    4324: 			format_add_modifier(&list, count, cp, 1, NULL, 0);
    4325: 			cp++;
    4326: 			continue;
    4327: 		}
    4328: 
    4329: 		/* Then try double character with no arguments. */
    4330: 		if ((memcmp("||", cp, 2) == 0 ||
    4331: 		    memcmp("&&", cp, 2) == 0 ||
    4332: 		    memcmp("!!", cp, 2) == 0 ||
    4333: 		    memcmp("!=", cp, 2) == 0 ||
    4334: 		    memcmp("==", cp, 2) == 0 ||
    4335: 		    memcmp("<=", cp, 2) == 0 ||
    4336: 		    memcmp(">=", cp, 2) == 0) &&
    4337: 		    format_is_end(cp[2])) {
    4338: 			format_add_modifier(&list, count, cp, 2, NULL, 0);
    4339: 			cp += 2;
    4340: 			continue;
    4341: 		}
    4342: 
    4343: 		/* Now try single character with arguments. */
    4344: 		if (strchr("mCLNPSst=pReqW", cp[0]) == NULL)
    4345: 			break;
    4346: 		c = cp[0];
    4347: 
    4348: 		/* No arguments provided. */
    4349: 		if (format_is_end(cp[1])) {
    4350: 			format_add_modifier(&list, count, cp, 1, NULL, 0);
    4351: 			cp++;
    4352: 			continue;
    4353: 		}
    4354: 		argv = NULL;
    4355: 		argc = 0;
    4356: 
    4357: 		/* Single argument with no wrapper character. */
    4358: 		if (!ispunct((u_char)cp[1]) || cp[1] == '-') {
    4359: 			end = format_skip(cp + 1, ":;");
    4360: 			if (end == NULL)
    4361: 				break;
    4362: 
>>  4363: 			argv = xcalloc(1, sizeof *argv);
    4364: 			value = xstrndup(cp + 1, end - (cp + 1));
    4365: 			argv[0] = format_expand1(es, value);
    4366: 			free(value);
    4367: 			argc = 1;
    4368: 
    4369: 			format_add_modifier(&list, count, &c, 1, argv, argc);
    4370: 			cp = end;
    4371: 			continue;
    4372: 		}
    4373: 
    4374: 		/* Multiple arguments with a wrapper character. */
    4375: 		last[0] = cp[1];
    4376: 		cp++;
    4377: 		do {
    4378: 			if (cp[0] == last[0] && format_is_end(cp[1])) {
    4379: 				cp++;
    4380: 				break;
    4381: 			}
    4382: 			end = format_skip(cp + 1, last);
    4383: 			if (end == NULL)
    4384: 				break;
    4385: 			cp++;
    4386: 
    4387: 			argv = xreallocarray(argv, argc + 1, sizeof *argv);
    4388: 			value = xstrndup(cp, end - cp);
    4389: 			argv[argc++] = format_expand1(es, value);
    4390: 			free(value);
    4391: 
    4392: 			cp = end;
    4393: 		} while (!format_is_end(cp[0]));
    4394: 		format_add_modifier(&list, count, &c, 1, argv, argc);
    4395: 	}
    4396: 	if (*cp != ':') {
    4397: 		format_free_modifiers(list, *count);
    4398: 		*count = 0;
    4399: 		return (NULL);
    4400: 	}
    4401: 	*s = cp + 1;
    4402: 	return (list);
    4403: }

