     452: tty_keys_add1(struct tty_key **tkp, const char *s, key_code key)
     453: {
     454: 	struct tty_key	*tk;
     455: 
     456: 	/* Allocate a tree entry if there isn't one already. */
     457: 	tk = *tkp;
     458: 	if (tk == NULL) {
>>   459: 		tk = *tkp = xcalloc(1, sizeof *tk);
