     461: 		tk->key = KEYC_UNKNOWN;
     462: 	}
     463: 
     464: 	/* Find the next entry. */
     465: 	if (*s == tk->ch) {
     466: 		/* Move forward in string. */
     467: 		s++;
     468: 
     469: 		/* If this is the end of the string, no more is necessary. */
     470: 		if (*s == '\0') {
     471: 			tk->key = key;
     472: 			return;
     473: 		}
     474: 
     475: 		/* Use the child tree for the next character. */
     476: 		tkp = &tk->next;
     477: 	} else {
     478: 		if (*s < tk->ch)
     479: 			tkp = &tk->left;
     480: 		else if (*s > tk->ch)
     481: 			tkp = &tk->right;
     482: 	}
     483: 
     484: 	/* And recurse to add it. */
     485: 	tty_keys_add1(tkp, s, key);
     486: }

