    3770: static char *
    3771: window_copy_stringify(struct grid *gd, u_int py, u_int first, u_int last,
    3772:     char *buf, u_int *size)
    3773: {
    3774: 	u_int			 ax, bx, newsize = *size;
    3775: 	const struct grid_line	*gl;
    3776: 	const char		*d;
    3777: 	size_t			 bufsize = 1024, dlen;
    3778: 	int			 allocated;
    3779: 
    3780: 	while (bufsize < newsize)
    3781: 		bufsize *= 2;
    3782: 	buf = xrealloc(buf, bufsize);
    3783: 
    3784: 	gl = grid_peek_line(gd, py);
    3785: 	if (gl == NULL) {
    3786: 		buf[*size - 1] = '\0';
    3787: 		return (buf);
    3788: 	}
    3789: 	bx = *size - 1;
    3790: 	for (ax = first; ax < last; ax++) {
>>  3791: 		d = window_copy_cellstring(gl, ax, &dlen, &allocated);
    3792: 		newsize += dlen;
    3793: 		while (bufsize < newsize) {
    3794: 			bufsize *= 2;
    3795: 			buf = xrealloc(buf, bufsize);
    3796: 		}
    3797: 		if (dlen == 1)
    3798: 			buf[bx++] = *d;
    3799: 		else {
    3800: 			memcpy(buf + bx, d, dlen);
    3801: 			bx += dlen;
    3802: 		}
>>  3803: 		if (allocated)
    3804: 			free((void *)d);
    3805: 	}
    3806: 	buf[newsize - 1] = '\0';
    3807: 
    3808: 	*size = newsize;
    3809: 	return (buf);
    3810: }

