     627: static void
     628: cmd_parse_free_argument(struct cmd_parse_argument *arg)
     629: {
>>   630: 	switch (arg->type) {
     631: 	case CMD_PARSE_STRING:
     632: 		free(arg->string);
     633: 		break;
     634: 	case CMD_PARSE_COMMANDS:
     635: 		cmd_parse_free_commands(arg->commands);
     636: 		break;
     637: 	case CMD_PARSE_PARSED_COMMANDS:
     638: 		cmd_list_free(arg->cmdlist);
     639: 		break;
     640: 	}
     641: 	free(arg);
