     767: static int
     768: cmd_parse_expand_alias(struct cmd_parse_command *cmd,
     769:     struct cmd_parse_input *pi, struct cmd_parse_result *pr)
     770: {
     771: 	struct cmd_parse_argument	*first;
     772: 	struct cmd_parse_commands	*cmds;
     773: 	struct cmd_parse_command	*last;
     774: 	char				*alias, *name, *cause;
     775: 
>>   776: 	if (pi->flags & CMD_PARSE_NOALIAS)
     777: 		return (0);
     778: 	memset(pr, 0, sizeof *pr);
     779: 
     780: 	first = TAILQ_FIRST(&cmd->arguments);
     781: 	if (first == NULL || first->type != CMD_PARSE_STRING) {
     782: 		pr->status = CMD_PARSE_SUCCESS;
     783: 		pr->cmdlist = cmd_list_new();
     784: 		return (1);
     785: 	}
     786: 	name = first->string;
     787: 
     788: 	alias = cmd_get_alias(name);
     789: 	if (alias == NULL)
     790: 		return (0);
     791: 	log_debug("%s: %u alias %s = %s", __func__, pi->line, name, alias);
     792: 
     793: 	cmds = cmd_parse_do_buffer(alias, strlen(alias), pi, &cause);
     794: 	free(alias);
>>   795: 	if (cmds == NULL) {
     796: 		pr->status = CMD_PARSE_ERROR;
     797: 		pr->error = cause;
     798: 		return (1);
     799: 	}
     800: 
     801: 	last = TAILQ_LAST(cmds, cmd_parse_commands);
>>   802: 	if (last == NULL) {
     803: 		pr->status = CMD_PARSE_SUCCESS;
     804: 		pr->cmdlist = cmd_list_new();
     805: 		return (1);
     806: 	}
     807: 
     808: 	TAILQ_REMOVE(&cmd->arguments, first, entry);
     809: 	cmd_parse_free_argument(first);
     810: 
     811: 	TAILQ_CONCAT(&last->arguments, &cmd->arguments, entry);
     812: 	cmd_parse_log_commands(cmds, __func__);
     813: 
     814: 	pi->flags |= CMD_PARSE_NOALIAS;
     815: 	cmd_parse_build_commands(cmds, pi, pr);
     816: 	pi->flags &= ~CMD_PARSE_NOALIAS;
     817: 	return (1);
     818: }

     876: static void
     877: cmd_parse_build_commands(struct cmd_parse_commands *cmds,
     878:     struct cmd_parse_input *pi, struct cmd_parse_result *pr)
     879: {
     880: 	struct cmd_parse_command	*cmd;
     881: 	u_int				 line = UINT_MAX;
     882: 	struct cmd_list			*current = NULL, *result;
     883: 	char				*s;
     884: 
     885: 	memset(pr, 0, sizeof *pr);
     886: 
     887: 	/* Check for an empty list. */
     888: 	if (TAILQ_EMPTY(cmds)) {
     889: 		pr->status = CMD_PARSE_SUCCESS;
     890: 		pr->cmdlist = cmd_list_new();
     891: 		return;
     892: 	}
     893: 	cmd_parse_log_commands(cmds, __func__);
     894: 
     895: 	/*
     896: 	 * Parse each command into a command list. Create a new command list
     897: 	 * for each line (unless the flag is set) so they get a new group (so
     898: 	 * the queue knows which ones to remove if a command fails when
     899: 	 * executed).
     900: 	 */
     901: 	result = cmd_list_new();
>>   902: 	TAILQ_FOREACH(cmd, cmds, entry) {
     903: 		if (((~pi->flags & CMD_PARSE_ONEGROUP) && cmd->line != line)) {
     904: 			if (current != NULL) {
     905: 				cmd_parse_print_commands(pi, current);
     906: 				cmd_list_move(result, current);
     907: 				cmd_list_free(current);
     908: 			}
     909: 			current = cmd_list_new();
     910: 		}
     911: 		if (current == NULL)
     912: 			current = cmd_list_new();
     913: 		line = pi->line = cmd->line;
     914: 
     915: 		cmd_parse_build_command(cmd, pi, pr);
     916: 		if (pr->status != CMD_PARSE_SUCCESS) {
     917: 			cmd_list_free(result);
     918: 			cmd_list_free(current);
     919: 			return;
     920: 		}
     921: 		cmd_list_append_all(current, pr->cmdlist);
     922: 		cmd_list_free(pr->cmdlist);
     923: 	}
     924: 	if (current != NULL) {
     925: 		cmd_parse_print_commands(pi, current);
     926: 		cmd_list_move(result, current);
     927: 		cmd_list_free(current);
     928: 	}
     929: 
     930: 	s = cmd_list_print(result, 0);
     931: 	log_debug("%s: %s", __func__, s);
     932: 	free(s);
     933: 
     934: 	pr->status = CMD_PARSE_SUCCESS;
     935: 	pr->cmdlist = result;
     936: }

