     172: 		cmdq_error(item, "client is read-only");
     173: 		return (CMD_RETURN_ERROR);
     174: 	}
     175: 
     176: 	if (args_has(args, 'N')) {
     177: 		np = args_strtonum_and_expand(args, 'N', 1, UINT_MAX, item,
     178: 			 &cause);
