     180: 			cmdq_error(item, "repeat count %s", cause);
     181: 			free(cause);
     182: 			return (CMD_RETURN_ERROR);
     183: 		}
     184: 		if (wme != NULL && (args_has(args, 'X') || count == 0)) {
     185: 			if (wme->mode->command == NULL) {
     186: 				cmdq_error(item, "not in a mode");
