     211: 		return (CMD_RETURN_NORMAL);
     212: 	}
     213: 
     214: 	if (cmd_get_entry(self) == &cmd_send_prefix_entry) {
     215: 		if (args_has(args, '2'))
     216: 			key = options_get_number(s->options, "prefix2");
