     218: 			key = options_get_number(s->options, "prefix");
>>   219: 		cmd_send_keys_inject_key(item, item, args, key);
     220: 		return (CMD_RETURN_NORMAL);
     221: 	}
     222: 
     223: 	if (args_has(args, 'R')) {
     224: 		colour_palette_clear(&wp->palette);
     225: 		input_reset(wp->ictx, 1);
     226: 		wp->flags |= (PANE_STYLECHANGED|PANE_THEMECHANGED|PANE_REDRAW);
     227: 	}
     228: 
     229: 	if (count == 0) {
