     231: 			return (CMD_RETURN_NORMAL);
     232: 		for (; np != 0; np--)
     233: 			cmd_send_keys_inject_key(item, NULL, args, event->key);
     234: 		return (CMD_RETURN_NORMAL);
     235: 	}
     236: 
     237: 	for (; np != 0; np--) {
     238: 		for (i = 0; i < count; i++) {
