     228: out:
     229: 	free(argument);
     230: 	free(expanded);
     231: 	free(name);
     232: 	return (CMD_RETURN_NORMAL);
     233: 
     234: fail:
     235: 	free(argument);
     236: 	free(expanded);
     237: 	free(name);
     238: 	return (CMD_RETURN_ERROR);
     239: }

