      63: void
      64: menu_add_item(struct menu *menu, const struct menu_item *item,
      65:     struct cmdq_item *qitem, struct client *c, struct cmd_find_state *fs)
      66: {
      67: 	struct menu_item	*new_item;
      68: 	const char		*key = NULL, *cmd, *suffix = "";
      69: 	char			*s, *trimmed, *name;
      70: 	u_int			 width, max_width;
      71: 	int			 line;
      72: 	size_t			 keylen, slen;
      73: 
      74: 	line = (item == NULL || item->name == NULL || *item->name == '\0');
      75: 	if (line && menu->count == 0)
      76: 		return;
      77: 	if (line && menu->items[menu->count - 1].name == NULL)
      78: 		return;
      79: 
>>    80: 	menu->items = xreallocarray(menu->items, menu->count + 1,
      81: 	    sizeof *menu->items);
      82: 	new_item = &menu->items[menu->count++];
      83: 	memset(new_item, 0, sizeof *new_item);
      84: 
      85: 	if (line)
      86: 		return;
      87: 
      88: 	if (fs != NULL)
      89: 		s = format_single_from_state(qitem, item->name, c, fs);
      90: 	else
      91: 		s = format_single(qitem, item->name, c, NULL, NULL, NULL);
      92: 	if (*s == '\0') { /* no item if empty after format expanded */
      93: 		free(s);
      94: 		menu->count--;
      95: 		return;
      96: 	}
      97: 	max_width = c->tty.sx - 4;
      98: 
      99: 	slen = strlen(s);
     100: 	if (*s != '-' && item->key != KEYC_UNKNOWN && item->key != KEYC_NONE) {
     101: 		key = key_string_lookup_key(item->key, 0);
     102: 		keylen = strlen(key) + 3; /* 3 = space and two brackets */
     103: 
     104: 		/*
     105: 		 * Add the key if it is shorter than a quarter of the available
     106: 		 * space or there is space for the entire item text and the
     107: 		 * key.
     108: 		 */
     109: 		if (keylen <= max_width / 4)
     110: 			max_width -= keylen;
     111: 		else if (keylen >= max_width || slen >= max_width - keylen)
     112: 			key = NULL;
     113: 	}
     114: 
     115: 	if (slen > max_width) {
     116: 		max_width--;
     117: 		suffix = ">";
     118: 	}
     119: 	trimmed = format_trim_right(s, max_width);
     120: 	if (key != NULL) {
     121: 		xasprintf(&name, "%s%s#[default] #[align=right](%s)",
     122: 		    trimmed, suffix, key);
     123: 	} else
     124: 		xasprintf(&name, "%s%s", trimmed, suffix);
     125: 	free(trimmed);
     126: 
     127: 	new_item->name = name;
     128: 	free(s);
     129: 
     130: 	cmd = item->command;
     131: 	if (cmd != NULL) {
     132: 		if (fs != NULL)
     133: 			s = format_single_from_state(qitem, cmd, c, fs);
     134: 		else
     135: 			s = format_single(qitem, cmd, c, NULL, NULL, NULL);
     136: 	} else
     137: 		s = NULL;
     138: 	new_item->command = s;
     139: 	new_item->key = item->key;
     140: 
     141: 	width = format_width(new_item->name);
     142: 	if (*new_item->name == '-')
     143: 		width--;
     144: 	if (width > menu->width)
     145: 		menu->width = width;
     146: }

