     234: static void
     235: mode_tree_build_lines(struct mode_tree_data *mtd,
     236:     struct mode_tree_list *mtl, u_int depth)
     237: {
     238: 	struct mode_tree_item	*mti;
     239: 	struct mode_tree_line	*line;
     240: 	u_int			 i;
     241: 	int			 flat = 1;
     242: 
     243: 	mtd->depth = depth;
     244: 	if (depth > mtd->maxdepth)
     245: 		mtd->maxdepth = depth;
     246: 	TAILQ_FOREACH(mti, mtl, entry) {
     247: 		mtd->line_list = xreallocarray(mtd->line_list,
     248: 		    mtd->line_size + 1, sizeof *mtd->line_list);
     249: 
     250: 		line = &mtd->line_list[mtd->line_size++];
     251: 		line->item = mti;
     252: 		line->depth = depth;
     253: 		line->last = (mti == TAILQ_LAST(mtl, mode_tree_list));
     254: 
     255: 		mti->line = (mtd->line_size - 1);
     256: 		if (!TAILQ_EMPTY(&mti->children))
     257: 			flat = 0;
     258: 		if (mti->expanded)
     259: 			mode_tree_build_lines(mtd, &mti->children, depth + 1);
     260: 
     261: 		if (mtd->keycb != NULL) {
     262: 			mti->key = mtd->keycb(mtd->modedata, mti->itemdata,
     263: 			    mti->line);
     264: 			if (mti->key == KEYC_UNKNOWN)
     265: 				mti->key = KEYC_NONE;
     266: 		} else if (mti->line < 10)
     267: 			mti->key = '0' + mti->line;
     268: 		else if (mti->line < 36)
     269: 			mti->key = KEYC_META|('a' + mti->line - 10);
     270: 		else
     271: 			mti->key = KEYC_NONE;
     272: 		if (mti->key != KEYC_NONE) {
>>   273: 			mti->keystr = xstrdup(key_string_lookup_key(mti->key,
     274: 			    0));
     275: 			mti->keylen = strlen(mti->keystr);
     276: 		} else {
     277: 			mti->keystr = NULL;
     278: 			mti->keylen = 0;
     279: 		}
     280: 	}
     281: 	TAILQ_FOREACH(mti, mtl, entry) {
     282: 		for (i = 0; i < mtd->line_size; i++) {
     283: 			line = &mtd->line_list[i];
     284: 			if (line->item == mti)
     285: 				line->flat = flat;
     286: 		}
     287: 	}
     288: }

