     560: static int
     561: popup_key_cb(struct client *c, void *data, struct key_event *event)
     562: {
     563: 	struct popup_data	*pd = data;
     564: 	struct mouse_event	*m = &event->m;
     565: 	const char		*buf;
     566: 	size_t			 len;
     567: 	u_int			 px, py, x;
     568: 	enum { NONE, LEFT, RIGHT, TOP, BOTTOM } border = NONE;
     569: 
     570: 	if (pd->md != NULL) {
     571: 		if (menu_key_cb(c, pd->md, event) == 1) {
     572: 			pd->md = NULL;
     573: 			pd->menu = NULL;
     574: 			if (pd->close)
     575: 				server_client_clear_overlay(c);
     576: 			else
     577: 				server_redraw_client(c);
     578: 		}
     579: 		return (0);
     580: 	}
     581: 
     582: 	if (KEYC_IS_MOUSE(event->key)) {
     583: 		if (pd->dragging != OFF) {
     584: 			popup_handle_drag(c, pd, m);
     585: 			goto out;
     586: 		}
     587: 		if (m->x < pd->px ||
     588: 		    m->x > pd->px + pd->sx - 1 ||
     589: 		    m->y < pd->py ||
     590: 		    m->y > pd->py + pd->sy - 1) {
     591: 			if (MOUSE_BUTTONS(m->b) == MOUSE_BUTTON_3)
     592: 				goto menu;
     593: 			return (0);
     594: 		}
     595: 		if (pd->border_lines != BOX_LINES_NONE) {
     596: 			if (m->x == pd->px)
     597: 				border = LEFT;
     598: 			else if (m->x == pd->px + pd->sx - 1)
     599: 				border = RIGHT;
     600: 			else if (m->y == pd->py)
     601: 				border = TOP;
     602: 			else if (m->y == pd->py + pd->sy - 1)
     603: 				border = BOTTOM;
     604: 		}
     605: 		if ((m->b & MOUSE_MASK_MODIFIERS) == 0 &&
     606: 		    MOUSE_BUTTONS(m->b) == MOUSE_BUTTON_3 &&
     607: 		    (border == LEFT || border == TOP))
     608: 		    goto menu;
     609: 		if (((m->b & MOUSE_MASK_MODIFIERS) == MOUSE_MASK_META) ||
     610: 		    (border != NONE && !MOUSE_DRAG(m->lb))) {
     611: 			if (!MOUSE_DRAG(m->b))
     612: 				goto out;
     613: 			if (MOUSE_BUTTONS(m->lb) == MOUSE_BUTTON_1)
     614: 				pd->dragging = MOVE;
     615: 			else if (MOUSE_BUTTONS(m->lb) == MOUSE_BUTTON_3)
     616: 				pd->dragging = SIZE;
     617: 			pd->dx = m->lx - pd->px;
     618: 			pd->dy = m->ly - pd->py;
     619: 			goto out;
     620: 		}
     621: 	}
     622: 	if ((((pd->flags & (POPUP_CLOSEEXIT|POPUP_CLOSEEXITZERO)) == 0) ||
     623: 	    pd->job == NULL) &&
     624: 	    (event->key == '\033' || event->key == ('c'|KEYC_CTRL)))
     625: 		return (1);
     626: 	if (pd->job == NULL && (pd->flags & POPUP_CLOSEANYKEY) &&
     627: 	    !KEYC_IS_MOUSE(event->key) && !KEYC_IS_PASTE(event->key))
     628: 		return (1);
     629: 	if (pd->job != NULL) {
     630: 		if (KEYC_IS_MOUSE(event->key)) {
     631: 			/* Must be inside, checked already. */
     632: 			if (pd->border_lines == BOX_LINES_NONE) {
     633: 				px = m->x - pd->px;
     634: 				py = m->y - pd->py;
     635: 			} else {
     636: 				px = m->x - pd->px - 1;
     637: 				py = m->y - pd->py - 1;
     638: 			}
     639: 			if (!input_key_get_mouse(&pd->s, m, px, py, &buf, &len))
     640: 				return (0);
     641: 			bufferevent_write(job_get_event(pd->job), buf, len);
     642: 			return (0);
     643: 		}
     644: 		input_key(&pd->s, job_get_event(pd->job), event->key);
     645: 	}
     646: 	return (0);
     647: 
     648: menu:
>>   649: 	pd->menu = menu_create("");
     650: 	if (pd->flags & POPUP_INTERNAL) {
     651: 		menu_add_items(pd->menu, popup_internal_menu_items, NULL, c,
     652: 		    NULL);
     653: 	} else
     654: 		menu_add_items(pd->menu, popup_menu_items, NULL, c, NULL);
     655: 	if (m->x >= (pd->menu->width + 4) / 2)
     656: 		x = m->x - (pd->menu->width + 4) / 2;
     657: 	else
     658: 		x = 0;
     659: 	pd->md = menu_prepare(pd->menu, 0, 0, NULL, x, m->y, c,
     660: 	    BOX_LINES_DEFAULT, NULL, NULL, NULL, NULL, popup_menu_done, pd);
     661: 	c->flags |= CLIENT_REDRAWOVERLAY;
     662: 
     663: out:
     664: 	pd->lx = m->x;
     665: 	pd->ly = m->y;
     666: 	pd->lb = m->b;
     667: 	return (0);
     668: }

