    2371: static int
    2372: server_client_dispatch_identify(struct client *c, struct imsg *imsg)
    2373: {
    2374: 	const char	*data, *home;
    2375: 	size_t		 datalen;
    2376: 	int		 flags, feat;
    2377: 	uint64_t	 longflags;
    2378: 	char		*name;
    2379: 
    2380: 	if (c->flags & CLIENT_IDENTIFIED)
    2381: 		return (-1);
    2382: 
    2383: 	data = imsg->data;
    2384: 	datalen = imsg->hdr.len - IMSG_HEADER_SIZE;
    2385: 
    2386: 	switch (imsg->hdr.type)	{
    2387: 	case MSG_IDENTIFY_FEATURES:
    2388: 		if (datalen != sizeof feat)
    2389: 			return (-1);
    2390: 		memcpy(&feat, data, sizeof feat);
    2391: 		c->term_features |= feat;
    2392: 		log_debug("client %p IDENTIFY_FEATURES %s", c,
    2393: 		    tty_get_features(feat));
    2394: 		break;
    2395: 	case MSG_IDENTIFY_FLAGS:
    2396: 		if (datalen != sizeof flags)
    2397: 			return (-1);
    2398: 		memcpy(&flags, data, sizeof flags);
    2399: 		c->flags |= flags;
    2400: 		log_debug("client %p IDENTIFY_FLAGS %#x", c, flags);
    2401: 		break;
    2402: 	case MSG_IDENTIFY_LONGFLAGS:
    2403: 		if (datalen != sizeof longflags)
    2404: 			return (-1);
    2405: 		memcpy(&longflags, data, sizeof longflags);
    2406: 		c->flags |= longflags;
    2407: 		log_debug("client %p IDENTIFY_LONGFLAGS %#llx", c,
    2408: 		    (unsigned long long)longflags);
    2409: 		break;
    2410: 	case MSG_IDENTIFY_TERM:
    2411: 		if (datalen == 0 || data[datalen - 1] != '\0')
    2412: 			return (-1);
    2413: 		c->term_name = xstrdup(data);
    2414: 		log_debug("client %p IDENTIFY_TERM %s", c, data);
    2415: 		break;
    2416: 	case MSG_IDENTIFY_TERMINFO:
