    2148: status_prompt_complete(struct client *c, const char *word, u_int offset)
    2149: {
    2150: 	struct session	 *session;
    2151: 	const char	 *s, *colon;
    2152: 	char		**list = NULL, *copy = NULL, *out = NULL;
    2153: 	char		  flag = '\0';
    2154: 	u_int		  size = 0, i;
    2155: 
    2156: 	if (*word == '\0' &&
    2157: 	    c->prompt_type != PROMPT_TYPE_TARGET &&
    2158: 	    c->prompt_type != PROMPT_TYPE_WINDOW_TARGET)
    2159: 		return (NULL);
    2160: 
    2161: 	if (c->prompt_type != PROMPT_TYPE_TARGET &&
    2162: 	    c->prompt_type != PROMPT_TYPE_WINDOW_TARGET &&
    2163: 	    strncmp(word, "-t", 2) != 0 &&
    2164: 	    strncmp(word, "-s", 2) != 0) {
    2165: 		list = status_prompt_complete_list(&size, word, offset == 0);
    2166: 		if (size == 0)
    2167: 			out = NULL;
    2168: 		else if (size == 1)
    2169: 			xasprintf(&out, "%s ", list[0]);
    2170: 		else
    2171: 			out = status_prompt_complete_prefix(list, size);
    2172: 		goto found;
    2173: 	}
    2174: 
    2175: 	if (c->prompt_type == PROMPT_TYPE_TARGET ||
    2176: 	    c->prompt_type == PROMPT_TYPE_WINDOW_TARGET) {
    2177: 		s = word;
    2178: 		flag = '\0';
    2179: 	} else {
    2180: 		s = word + 2;
    2181: 		flag = word[1];
    2182: 		offset += 2;
    2183: 	}
    2184: 
    2185: 	/* If this is a window completion, open the window menu. */
    2186: 	if (c->prompt_type == PROMPT_TYPE_WINDOW_TARGET) {
    2187: 		out = status_prompt_complete_window_menu(c, c->session, s,
    2188: 		    offset, '\0');
