     544: 	term->tty = tty;
     545: 	term->name = xstrdup(name);
     546: 	term->codes = xcalloc(tty_term_ncodes(), sizeof *term->codes);
     547: 	LIST_INSERT_HEAD(&tty_terms, term, entry);
     548: 
     549: 	/* Fill in codes. */
     550: 	for (i = 0; i < ncaps; i++) {
     551: 		namelen = strcspn(caps[i], "=");
     552: 		if (namelen == 0)
     553: 			continue;
     554: 		value = caps[i] + namelen + 1;
     555: 
     556: 		for (j = 0; j < tty_term_ncodes(); j++) {
     557: 			ent = &tty_term_codes[j];
     558: 			if (strncmp(ent->name, caps[i], namelen) != 0)
     559: 				continue;
     560: 			if (ent->name[namelen] != '\0')
     561: 				continue;
     562: 
     563: 			code = &term->codes[j];
     564: 			code->type = TTYCODE_NONE;
     565: 			switch (ent->type) {
     566: 			case TTYCODE_NONE:
     567: 				break;
     568: 			case TTYCODE_STRING:
     569: 				code->type = TTYCODE_STRING;
     570: 				code->value.string = tty_term_strip(value);
     571: 				break;
     572: 			case TTYCODE_NUMBER:
     573: 				n = strtonum(value, 0, INT_MAX, &errstr);
     574: 				if (errstr != NULL)
     575: 					log_debug("%s: %s", ent->name, errstr);
     576: 				else {
     577: 					code->type = TTYCODE_NUMBER;
     578: 					code->value.number = n;
     579: 				}
     580: 				break;
     581: 			case TTYCODE_FLAG:
     582: 				code->type = TTYCODE_FLAG;
     583: 				code->value.flag = (*value == '1');
     584: 				break;
     585: 			}
     586: 		}
     587: 	}
