     589: 	/* Apply terminal features. */
     590: 	o = options_get_only(global_options, "terminal-features");
     591: 	a = options_array_first(o);
     592: 	while (a != NULL) {
     593: 		ov = options_array_item_value(a);
     594: 		s = ov->string;
     595: 
     596: 		offset = 0;
     597: 		first = tty_term_override_next(s, &offset);
     598: 		if (first != NULL && fnmatch(first, term->name, 0) == 0)
     599: 			tty_add_features(feat, s + offset, ":");
     600: 		a = options_array_next(a);
     601: 	}
     602: 
     603: 	/* Delete curses data. */
     604: #if !defined(NCURSES_VERSION_MAJOR) || NCURSES_VERSION_MAJOR > 5 || \
     605:     (NCURSES_VERSION_MAJOR == 5 && NCURSES_VERSION_MINOR > 6)
     606: 	del_curterm(cur_term);
     607: #endif
     608: 	/* Check for COLORTERM. */
     609: 	envent = environ_find(tty->client->environ, "COLORTERM");
     610: 	if (envent != NULL) {
     611: 		log_debug("%s COLORTERM=%s", tty->client->name, envent->value);
     612: 		if (strcasecmp(envent->value, "truecolor") == 0 ||
     613: 		    strcasecmp(envent->value, "24bit") == 0)
     614: 			tty_add_features(feat, "RGB", ",");
     615:  		else if (strstr(envent->value, "256") != NULL)
     616: 			tty_add_features(feat, "256", ",");
     617: 	}
     618: 
     619: 	/* Apply overrides so any capabilities used for features are changed. */
     620: 	tty_term_apply_overrides(term);
     621: 
     622: 	/* These are always required. */
>>   623: 	if (!tty_term_has(term, TTYC_CLEAR)) {
     624: 		xasprintf(cause, "terminal does not support clear");
     625: 		goto error;
     626: 	}
>>   627: 	if (!tty_term_has(term, TTYC_CUP)) {
     628: 		xasprintf(cause, "terminal does not support cup");
     629: 		goto error;
     630: 	}
     631: 
     632: 	/*
     633: 	 * If TERM has XT or clear starts with CSI then it is safe to assume
     634: 	 * the terminal is derived from the VT100. This controls whether device
     635: 	 * attributes requests are sent to get more information.
     636: 	 *
     637: 	 * This is a bit of a hack but there aren't that many alternatives.
     638: 	 * Worst case tmux will just fall back to using whatever terminfo(5)
     639: 	 * says without trying to correct anything that is missing.
     640: 	 *
     641: 	 * Also add few features that VT100-like terminals should either
     642: 	 * support or safely ignore.
     643: 	 */
     644: 	s = tty_term_string(term, TTYC_CLEAR);
     645: 	if (tty_term_flag(term, TTYC_XT) || strncmp(s, "\033[", 2) == 0) {
     646: 		term->flags |= TERM_VT100LIKE;
     647: 		tty_add_features(feat, "bpaste,focus,title", ",");
     648: 	}
     649: 
     650: 	/* Add RGB feature if terminal has RGB colours. */
     651: 	if ((tty_term_flag(term, TTYC_TC) || tty_term_has(term, TTYC_RGB)) &&
     652: 	    (!tty_term_has(term, TTYC_SETRGBF) ||
     653: 	    !tty_term_has(term, TTYC_SETRGBB)))
     654: 		tty_add_features(feat, "RGB", ",");
     655: 
     656: 	/* Apply the features and overrides again. */
     657: 	if (tty_apply_features(term, *feat))
     658: 		tty_term_apply_overrides(term);
     659: 
     660: 	/* Log the capabilities. */
     661: 	for (i = 0; i < tty_term_ncodes(); i++)
     662: 		log_debug("%s%s", name, tty_term_describe(term, i));
     663: 
     664: 	return (term);
     665: 
     666: error:
     667: 	tty_term_free(term);
     668: 	return (NULL);
     669: }

