     153: 		paste_buffer_data(l[i], &item->size);
     154: 		item->order = paste_buffer_order(l[i]);
     155: 	}
     156: 
     157: 	if (cmd_find_valid_state(&data->fs)) {
     158: 		s = data->fs.s;
