     116: static void
     117: window_client_build(void *modedata, struct sort_criteria *sort_crit,
     118:     __unused uint64_t *tag, const char *filter)
     119: {
     120: 	struct window_client_modedata	*data = modedata;
     121: 	struct window_client_itemdata	*item;
     122: 	u_int				 i, n;
     123: 	struct client			*c, **l;
     124: 	char				*text, *cp;
     125: 
     126: 	for (i = 0; i < data->item_size; i++)
     127: 		window_client_free_item(data->item_list[i]);
     128: 	free(data->item_list);
     129: 	data->item_list = NULL;
     130: 	data->item_size = 0;
     131: 
     132: 	l = sort_get_clients(&n, sort_crit);
     133: 	for (i = 0; i < n; i++) {
     134: 		if (l[i]->session == NULL ||
     135: 		    (l[i]->flags & CLIENT_UNATTACHEDFLAGS))
     136: 			continue;
     137: 
>>   138: 		item = window_client_add_item(data);
     139: 		item->c = l[i];
     140: 
     141: 		l[i]->references++;
     142: 	}
     143: 
     144: 	for (i = 0; i < data->item_size; i++) {
     145: 		item = data->item_list[i];
     146: 		c = item->c;
     147: 
     148: 		if (filter != NULL) {
     149: 			cp = format_single(NULL, filter, c, NULL, NULL, NULL);
     150: 			if (!format_true(cp)) {
     151: 				free(cp);
     152: 				continue;
     153: 			}
     154: 			free(cp);
     155: 		}
     156: 
     157: 		text = format_single(NULL, data->format, c, NULL, NULL, NULL);
     158: 		mode_tree_add(data->data, NULL, item, (uint64_t)c, c->name,
     159: 		    text, -1);
     160: 		free(text);
     161: 	}
     162: }

