    3562: static int
    3563: window_copy_search_lr_regex(struct grid *gd, u_int *ppx, u_int *psx, u_int py,
    3564:     u_int first, u_int last, regex_t *reg)
    3565: {
    3566: 	int			eflags = 0;
    3567: 	u_int			endline, foundx, foundy, len, pywrap, size = 1;
    3568: 	char		       *buf;
    3569: 	regmatch_t		regmatch;
    3570: 	struct grid_line       *gl;
    3571: 
    3572: 	/*
    3573: 	 * This can happen during search if the last match was the last
    3574: 	 * character on a line.
    3575: 	 */
    3576: 	if (first >= last)
    3577: 		return (0);
    3578: 
    3579: 	/* Set flags for regex search. */
    3580: 	if (first != 0)
    3581: 		eflags |= REG_NOTBOL;
    3582: 
    3583: 	/* Need to look at the entire string. */
>>  3584: 	buf = xmalloc(size);
    3585: 	buf[0] = '\0';
    3586: 	buf = window_copy_stringify(gd, py, first, gd->sx, buf, &size);
    3587: 	len = gd->sx - first;
    3588: 	endline = gd->hsize + gd->sy - 1;
    3589: 	pywrap = py;
    3590: 	while (buf != NULL &&
    3591: 	    pywrap <= endline &&
    3592: 	    len < WINDOW_COPY_SEARCH_MAX_LINE) {
    3593: 		gl = grid_get_line(gd, pywrap);
    3594: 		if (~gl->flags & GRID_LINE_WRAPPED)
    3595: 			break;
    3596: 		pywrap++;
    3597: 		buf = window_copy_stringify(gd, pywrap, 0, gd->sx, buf, &size);
    3598: 		len += gd->sx;
    3599: 	}
    3600: 
    3601: 	if (regexec(reg, buf, 1, &regmatch, eflags) == 0 &&
    3602: 	    regmatch.rm_so != regmatch.rm_eo) {
    3603: 		foundx = first;
    3604: 		foundy = py;
    3605: 		window_copy_cstrtocellpos(gd, len, &foundx, &foundy,
    3606: 		    buf + regmatch.rm_so);
    3607: 		if (foundy == py && foundx < last) {
    3608: 			*ppx = foundx;
    3609: 			len -= foundx - first;
    3610: 			window_copy_cstrtocellpos(gd, len, &foundx, &foundy,
    3611: 			    buf + regmatch.rm_eo);
    3612: 			*psx = foundx;
    3613: 			while (foundy > py) {
    3614: 				*psx += gd->sx;
    3615: 				foundy--;
    3616: 			}
    3617: 			*psx -= *ppx;
    3618: 			free(buf);
    3619: 			return (1);
    3620: 		}
    3621: 	}
    3622: 
    3623: 	free(buf);
    3624: 	*ppx = 0;
    3625: 	*psx = 0;
    3626: 	return (0);
    3627: }

