    4308: static int
    4309: window_copy_search_marks(struct window_mode_entry *wme, struct screen *ssp,
    4310:     int regex, int visible_only)
    4311: {
    4312: 	struct window_copy_mode_data	*data = wme->data;
    4313: 	struct screen			*s = data->backing, ss;
    4314: 	struct screen_write_ctx		 ctx;
    4315: 	struct grid			*gd = s->grid;
    4316: 	struct grid_cell		 gc;
    4317: 	int				 found, cis, stopped = 0;
    4318: 	int				 cflags = REG_EXTENDED;
    4319: 	u_int				 px, py, nfound = 0, width;
    4320: 	u_int				 ssize = 1, start, end, sx = gd->sx;
    4321: 	u_int				 sy = gd->sy;
    4322: 	char				*sbuf;
    4323: 	regex_t				 reg;
    4324: 	uint64_t			 stop = 0, tstart, t;
    4325: 
    4326: 	if (ssp == NULL) {
    4327: 		width = screen_write_strlen("%s", data->searchstr);
    4328: 		screen_init(&ss, width, 1, 0);
    4329: 		screen_write_start(&ctx, &ss);
    4330: 		screen_write_nputs(&ctx, -1, &grid_default_cell, "%s",
    4331: 		    data->searchstr);
    4332: 		screen_write_stop(&ctx);
    4333: 		ssp = &ss;
    4334: 	} else
    4335: 		width = screen_size_x(ssp);
    4336: 
    4337: 	cis = window_copy_is_lowercase(data->searchstr);
    4338: 
    4339: 	if (regex) {
    4340: 		sbuf = xmalloc(ssize);
    4341: 		sbuf[0] = '\0';
    4342: 		sbuf = window_copy_stringify(ssp->grid, 0, 0, ssp->grid->sx,
    4343: 		    sbuf, &ssize);
    4344: 		if (cis)
    4345: 			cflags |= REG_ICASE;
    4346: 		if (regcomp(&reg, sbuf, cflags) != 0) {
    4347: 			free(sbuf);
    4348: 			return (0);
    4349: 		}
    4350: 		free(sbuf);
    4351: 	}
    4352: 	tstart = get_timer();
    4353: 
    4354: 	if (visible_only)
    4355: 		window_copy_visible_lines(data, &start, &end);
    4356: 	else {
    4357: 		start = 0;
    4358: 		end = gd->hsize + sy;
    4359: 		stop = get_timer() + WINDOW_COPY_SEARCH_ALL_TIMEOUT;
    4360: 	}
    4361: 
    4362: again:
    4363: 	free(data->searchmark);
>>  4364: 	data->searchmark = xcalloc(sx, sy);
    4365: 	data->searchgen = 1;
    4366: 
    4367: 	for (py = start; py < end; py++) {
    4368: 		px = 0;
    4369: 		for (;;) {
    4370: 			if (regex) {
    4371: 				found = window_copy_search_lr_regex(gd,
    4372: 				    &px, &width, py, px, sx, &reg);
    4373: 				grid_get_cell(gd, px + width - 1, py, &gc);
    4374: 				if (gc.data.width > 2)
    4375: 					width += gc.data.width - 1;
    4376: 				if (!found)
    4377: 					break;
    4378: 			} else {
    4379: 				found = window_copy_search_lr(gd, ssp->grid,
    4380: 				    &px, py, px, sx, cis);
    4381: 				if (!found)
    4382: 					break;
    4383: 			}
    4384: 			nfound++;
    4385: 			px += window_copy_search_mark_match(data, px, py, width,
    4386: 			    regex);
    4387: 		}
    4388: 
    4389: 		t = get_timer();
    4390: 		if (t - tstart > WINDOW_COPY_SEARCH_TIMEOUT) {
    4391: 			data->timeout = 1;
    4392: 			break;
    4393: 		}
    4394: 		if (stop != 0 && t > stop) {
    4395: 			stopped = 1;
    4396: 			break;
    4397: 		}
    4398: 	}
    4399: 	if (data->timeout) {
    4400: 		window_copy_clear_marks(wme);
    4401: 		goto out;
    4402: 	}
    4403: 
    4404: 	if (stopped && stop != 0) {
    4405: 		/* Try again but just the visible context. */
    4406: 		window_copy_visible_lines(data, &start, &end);
    4407: 		stop = 0;
    4408: 		goto again;
    4409: 	}
    4410: 
    4411: 	if (!visible_only) {
    4412: 		if (stopped) {
    4413: 			if (nfound > 1000)
    4414: 				data->searchcount = 1000;
    4415: 			else if (nfound > 100)
    4416: 				data->searchcount = 100;
    4417: 			else if (nfound > 10)
    4418: 				data->searchcount = 10;
    4419: 			else
    4420: 				data->searchcount = -1;
    4421: 			data->searchmore = 1;
    4422: 		} else {
    4423: 			data->searchcount = nfound;
    4424: 			data->searchmore = 0;
    4425: 		}
    4426: 	}
    4427: 
    4428: out:
    4429: 	if (ssp == &ss)
    4430: 		screen_free(&ss);
    4431: 	if (regex)
    4432: 		regfree(&reg);
    4433: 	return (1);
    4434: }

