    4497: static char *
    4498: window_copy_match_at_cursor(struct window_copy_mode_data *data)
    4499: {
    4500: 	struct grid	*gd = data->backing->grid;
    4501: 	struct grid_cell gc;
    4502: 	u_int		 at, start, end, cy, px, py;
    4503: 	u_int		 sx = screen_size_x(data->backing);
    4504: 	char		*buf = NULL;
    4505: 	size_t		 len = 0;
    4506: 
    4507: 	if (data->searchmark == NULL)
    4508: 		return (NULL);
    4509: 
    4510: 	cy = screen_hsize(data->backing) - data->oy + data->cy;
    4511: 	if (window_copy_search_mark_at(data, data->cx, cy, &at) != 0)
    4512: 		return (NULL);
    4513: 	if (data->searchmark[at] == 0) {
    4514: 		/* Allow one position after the match. */
    4515: 		if (at == 0 || data->searchmark[--at] == 0)
    4516: 			return (NULL);
    4517: 	}
    4518: 	window_copy_match_start_end(data, at, &start, &end);
    4519: 
    4520: 	/*
    4521: 	 * Cells will not be set in the marked array unless they are valid text
    4522: 	 * and wrapping will be taken care of, so we can just copy.
    4523:  	 */
    4524: 	for (at = start; at <= end; at++) {
    4525: 		py = at / sx;
    4526: 		px = at - (py * sx);
    4527: 
    4528: 		grid_get_cell(gd, px, gd->hsize + py - data->oy, &gc);
    4529: 		if (gc.flags & GRID_FLAG_TAB) {
>>  4530: 			buf = xrealloc(buf, len + 2);
    4531: 			buf[len] = '\t';
    4532: 			len++;
    4533: 		} else if (gc.flags & GRID_FLAG_PADDING) {
    4534: 			/* nothing to do */
    4535: 		} else {
    4536: 			buf = xrealloc(buf, len + gc.data.size + 1);
    4537: 			memcpy(buf + len, gc.data.data, gc.data.size);
    4538: 			len += gc.data.size;
    4539: 		}
    4540: 	}
    4541: 	if (len != 0)
    4542: 		buf[len] = '\0';
    4543: 	return (buf);
    4544: }

