    1089: 				break;
    1090: 			case WINDOW_CUSTOMIZE_GLOBAL_SESSION:
    1091: 				scope = WINDOW_CUSTOMIZE_SESSION;
    1092: 				break;
    1093: 			case WINDOW_CUSTOMIZE_GLOBAL_WINDOW:
    1094: 				if (pane)
    1095: 					scope = WINDOW_CUSTOMIZE_PANE;
    1096: 				else
    1097: 					scope = WINDOW_CUSTOMIZE_WINDOW;
    1098: 				break;
    1099: 			}
    1100: 		}
    1101: 		if (scope == item->scope)
