    1129: 				    space, text);
    1130: 			}
    1131: 		} else
    1132: 			xasprintf(&prompt, "(%s%s%s) ", name, space, text);
    1133: 		free(text);
    1134: 
    1135: 		value = options_to_string(o, idx, 0);
    1136: 
    1137: 		new_item = xcalloc(1, sizeof *new_item);
    1138: 		new_item->data = data;
    1139: 		new_item->scope = scope;
    1140: 		new_item->oo = oo;
>>  1141: 		new_item->name = xstrdup(name);
