     465: 
     466: 	bd = key_bindings_first(kt);
     467: 	while (bd != NULL) {
     468: 		format_add(ft, "key", "%s", key_string_lookup_key(bd->key, 0));
     469: 		if (bd->note != NULL)
     470: 			format_add(ft, "key_note", "%s", bd->note);
     471: 		if (filter != NULL) {
     472: 			expanded = format_expand(ft, filter);
