     511: 		if (bd->flags & KEY_BINDING_REPEAT)
     512: 			flag = "on";
     513: 		else
     514: 			flag = "off";
     515: 		mti = mode_tree_add(data->data, child, item,
     516: 		    tag|(bd->key << 3)|(2 << 1)|1, "Repeat", flag, -1);
