     303: static void
     304: window_tree_build_session(struct session *s, void *modedata,
     305:     struct sort_criteria *sort_crit, const char *filter)
     306: {
     307: 	struct window_tree_modedata	*data = modedata;
     308: 	struct window_tree_itemdata	*item;
     309: 	struct mode_tree_item		*mti;
     310: 	char				*text;
     311: 	struct winlink			*wl = s->curw, **l;
     312: 	u_int				 n, i, empty;
     313: 	int				 expanded;
     314: 	struct format_tree		*ft;
     315: 
>>   316: 	item = window_tree_add_item(data);
     317: 	item->type = WINDOW_TREE_SESSION;
     318: 	item->session = s->id;
     319: 	item->winlink = -1;
     320: 	item->pane = -1;
     321: 
     322: 	ft = format_create(NULL, NULL, FORMAT_PANE|wl->window->active->id, 0);
     323: 	format_defaults(ft, NULL, s, NULL, NULL);
     324: 	text = format_expand(ft, data->format);
     325: 	format_free(ft);
     326: 
     327: 	if (data->type == WINDOW_TREE_SESSION)
     328: 		expanded = 0;
     329: 	else
     330: 		expanded = 1;
     331: 	mti = mode_tree_add(data->data, NULL, item, (uint64_t)s, s->name, text,
     332: 	    expanded);
     333: 	free(text);
     334: 
     335: 	l = sort_get_winlinks_session(s, &n, sort_crit);
     336: 	empty = 0;
     337: 	for (i = 0; i < n; i++) {
     338: 		if (!window_tree_build_window(s, l[i], modedata, sort_crit, mti,
     339: 		    filter))
     340: 			empty++;
     341: 	}
     342: 	if (empty == n) {
     343: 		window_tree_free_item(item);
     344: 		data->item_size--;
     345: 		mode_tree_remove(data->data, mti);
     346: 	}
     347: }

